const body = $json.body || $json;
return [{ json: {
  request_id: 'r-' + Date.now(),
  prompt: body.prompt || '',
  policy_mode: body.policy_mode || 'balanced',
  dept_id: body.dept_id || 'demo-support',
  task_type: body.task_type || 'general'
} }];

const outGuard = $json;
const cache = $('Cache Lookup').item.json;
const guardrail = $('Guardrails').item.json;
const cachedAnswer = cache.answer;

let answer;
let outStatus;
if (outGuard.pass === false) {
  answer = 'The generated response was blocked by the output guardrail.';
  outStatus = 'blocked';
} else {
  answer = (outGuard.redacted_text && outGuard.redacted_text !== cachedAnswer) ? outGuard.redacted_text : cachedAnswer;
  outStatus = 'passed';
}

return [{ json: {
  answer: answer,
  receipt: {
    guardrail_status: 'passed',
    output_guardrail_status: outStatus,
    output_guardrail_issues: outGuard.issues || [],
    cache_status: 'hit',
    cache_confidence: cache.confidence,
    cache_entry_id: cache.entry_id,
    selected_tier: 'cache',
    estimated_tokens: (cache.estimated_tokens != null ? cache.estimated_tokens : 0),
    estimated_cost: 0,
    optimization_reason: 'semantic_cache_hit',
    cost_saved: (cache.cost_saved != null ? cache.cost_saved : 0),
    detected_risk_type: guardrail.detected_risk_type || null,
    reason: 'semantic_cache_hit',
    savings_source: 'semantic_cache',
    savings_reason: 'semantic_cache_hit'
  }
} }];

// Mock model provider. Real Ollama / external LLM comes later. It receives
// and preserves the optimizer's selected tier + plan for traceability.
const opt = $('Optimizer').item.json;
return [{ json: {
  answer: 'This is a mock answer from TokenWise (Day 1-5 skeleton). Real model routing comes later.',
  selected_tier: opt.selected_tier,
  optimization_plan: opt.optimization_plan,
  decision_reasons: opt.decision_reasons
} }];

const outGuard = $('Guardrails Output').item.json;
const optimizer = $('Optimizer').item.json;
const guardrail = $('Guardrails').item.json;
const cache = $('Cache Lookup').item.json;
const modelAnswer = $('Mock Model').item.json.answer;

let answer;
let outStatus;
if (outGuard.pass === false) {
  answer = 'The generated response was blocked by the output guardrail.';
  outStatus = 'blocked';
} else {
  answer = (outGuard.redacted_text && outGuard.redacted_text !== modelAnswer) ? outGuard.redacted_text : modelAnswer;
  outStatus = 'passed';
}

const inStatus = guardrail.requires_redaction ? 'passed_with_redaction' : 'passed';

return [{ json: {
  answer: answer,
  receipt: {
    guardrail_status: inStatus,
    output_guardrail_status: outStatus,
    output_guardrail_issues: outGuard.issues || [],
    cache_status: 'miss',
    cache_confidence: (cache.confidence != null ? cache.confidence : 0),
    cache_entry_id: null,
    selected_tier: optimizer.selected_tier,
    estimated_tokens: optimizer.estimated_tokens,
    estimated_cost: optimizer.estimated_cost,
    optimization_reason: optimizer.optimization_reason,
    cost_saved: optimizer.cost_saved,
    detected_risk_type: guardrail.detected_risk_type || null,
    reason: guardrail.reason || 'passed',
    savings_source: 'model_routing',
    savings_reason: 'cheaper_model_selected',
    task_type: optimizer.task_type,
    complexity_score: optimizer.complexity_score,
    complexity_level: optimizer.complexity_level,
    compression_recommended: optimizer.compression_recommended,
    compression_target_ratio: optimizer.compression_target_ratio,
    compression_reason: optimizer.compression_reason,
    compression_risk: optimizer.compression_risk,
    fallback_tier: optimizer.fallback_tier,
    estimated_baseline_cost: optimizer.estimated_baseline_cost,
    estimated_optimized_cost: optimizer.estimated_optimized_cost,
    decision_reasons: optimizer.decision_reasons || []
  }
} }];

const g = $json;
const tokens = (g.estimated_tokens != null) ? g.estimated_tokens : 0;
const saved = g.cost_saved_by_blocking || 0;
return [{ json: {
  answer: 'Request blocked by TokenWise guardrails: ' + (g.reason || 'blocked'),
  receipt: {
    guardrail_status: 'blocked',
    output_guardrail_status: 'skipped',
    output_guardrail_issues: [],
    cache_status: 'skipped',
    cache_confidence: 0,
    cache_entry_id: null,
    selected_tier: 'none',
    estimated_tokens: tokens,
    estimated_cost: 0,
    optimization_reason: 'Blocked: ' + (g.reason || '') + (g.policy_triggered ? ' [' + g.policy_triggered + ']' : ''),
    cost_saved: saved,
    detected_risk_type: g.detected_risk_type || null,
    reason: g.reason || 'blocked',
    savings_source: 'guardrails_cost_governance',
    savings_reason: g.reason || 'blocked'
  }
} }];
